const trigger = $('Workflow Trigger').first().json;
const targetOrderNumber = String(trigger.order_number || '').replace(/\D/g, '');
const targetPhone = String(trigger.phone || '').replace(/\D/g, '');
const docs = $input.all().map((entry) => entry.json).filter((entry) => entry && entry.document);

const parseField = (field) => {
  if (!field || typeof field !== 'object') return field;
  if (field.stringValue !== undefined) return field.stringValue;
  if (field.integerValue !== undefined) return Number(field.integerValue);
  if (field.doubleValue !== undefined) return Number(field.doubleValue);
  if (field.booleanValue !== undefined) return field.booleanValue;
  if (field.timestampValue !== undefined) return field.timestampValue;
  if (field.nullValue !== undefined) return null;
  if (field.arrayValue) return (field.arrayValue.values || []).map(parseField);
  if (field.mapValue) {
    const obj = {};
    for (const [key, value] of Object.entries(field.mapValue.fields || {})) {
      obj[key] = parseField(value);
    }
    return obj;
  }
  return null;
};

const normalizePhone = (value = '') => String(value).replace(/\D/g, '');
const describeStatus = (saleStatus, orderStatus) => {
  if (saleStatus === 'payment_sent') {
    return 'aguardando pagamento';
  }
  switch (orderStatus) {
    case 'awaiting_processing':
    case 'separating':
      return 'aguardando processamento';
    case 'preparing':
      return 'em preparacao';
    case 'packing':
      return 'embalando';
    case 'awaiting_pickup':
      return 'aguardando retirada';
    case 'ready_for_pickup':
    case 'ready_for_shipping':
    case 'ready':
      return 'pronto para envio ou retirada';
    case 'shipped':
      return 'enviado';
    case 'completed':
      return 'concluido';
    default:
      return saleStatus === 'confirmed' ? 'em andamento' : 'aguardando definicao';
  }
};

const sales = docs
  .map((raw) => {
    const fields = raw.document.fields || {};
    const items = parseField(fields.items) || [];
    const publicOrderNumber = String(parseField(fields.public_order_number) || '').trim();
    const customerWhatsapp = normalizePhone(parseField(fields.customer_whatsapp) || '');
    return {
      sale_id: raw.document.name.split('/').pop(),
      order_number: publicOrderNumber,
      order_number_label: publicOrderNumber ? `#${publicOrderNumber}` : '',
      status: String(parseField(fields.status) || '').trim(),
      order_status: String(parseField(fields.order_status) || '').trim(),
      customer_id: String(parseField(fields.customer_id) || '').trim(),
      customer_whatsapp: customerWhatsapp,
      total: Number(parseField(fields.total) || 0),
      customer_name: String(parseField(fields.customer_name) || '').trim(),
      items,
      created_at: String(parseField(fields.created_at) || '').trim(),
      current_status_label: describeStatus(
        String(parseField(fields.status) || '').trim(),
        String(parseField(fields.order_status) || '').trim(),
      ),
    };
  })
  .filter((sale) => sale.status && sale.status !== 'cancelled')
  .filter((sale) => !targetPhone || !sale.customer_whatsapp || sale.customer_whatsapp === targetPhone);

let matchedSale = null;
if (targetOrderNumber) {
  matchedSale = sales.find((sale) => sale.order_number === targetOrderNumber) || null;
}
if (!matchedSale) {
  matchedSale = sales[0] || null;
}

if (!matchedSale) {
  return [{ json: { success: false, found: false, message: 'Nenhum pedido encontrado para este cliente.' } }];
}

return [{
  json: {
    success: true,
    found: true,
    ...matchedSale,
  }
}];
